// 1. Form Trigger nodundan gelen verileri yakalıyoruz
const formData = $('Form Trigger').first().json;

const scenarioName = formData.scenarioName;
const targetUrl = formData.targetUrl;

const steps = [];

// 2. Dinamik olarak Adım 1'i inşa ediyoruz
if (formData.step1_type && formData.step1_instruction) {
    steps.push({
        type: formData.step1_type,
        instruction: formData.step1_instruction
    });
}

// 3. Dinamik olarak Adım 2'yi inşa ediyoruz
if (formData.step2_type && formData.step2_instruction) {
    let step2Obj = {
        type: formData.step2_type,
        instruction: formData.step2_instruction
    };

    // Eğer kullanıcı extract seçtiyse ve alan adı girdiyse ekle
    if (formData.step2_field) {
        step2Obj.field = formData.step2_field;
    }

    steps.push(step2Obj);
}

// Oluşturulan temiz JSON metni
const finalJsonString = JSON.stringify({
  targetUrl: targetUrl,
  steps: steps
}, null, 2);

// 4. Node.js ile diske yazma katmanı (Mevcut güvenli kodumuz aynen kalıyor)
const fs = require('fs');
const path = require('path');
const targetFolder = 'C:/Users/feyza/Desktop/test-tool/scenarios';
const fullPath = path.join(targetFolder, `${scenarioName}.json`);

try {
    if (!fs.existsSync(targetFolder)){
        fs.mkdirSync(targetFolder, { recursive: true });
    }

    fs.writeFileSync(fullPath, finalJsonString, 'utf-8');

    return [{
      json: {
        status: "Başarılı",
        message: `Form verisi başarıyla JSON senaryosuna dönüştürüldü ve kaydedildi!`,
        scenario: `${scenarioName}.json`
      }
    }];

} catch (writeError) {
    return [{
      json: {
        status: "Hata",
        message: writeError.message
      }
    }];
}
